mapper.select:
select r.id, r.reporter_id, m.nickname as reporter_nickname, case r.target_type when 'WORK' then '작품' when 'MEMBER' then '회원' when 'COMMENT' then '댓글' when 'GALLERY' then '예술관' else r.target_type end as category, r.target_type, r.target_id, case r.reason when 'SENSITIVE' then '음란/선정' when 'IMPERSONATION' then '사칭' when 'HARASSMENT' then '괴롭힘' when 'COPYRIGHT' then '저작권' else r.reason end as reason, r.detail as reason_detail, r.detail, r.status, r.resolved_at, r.resolved_at as processed_at, r.created_datetime as created_at, case when r.target_type = 'WORK' then ( select w.title from tbl_work w where w.id = r.target_id ) when r.target_type = 'MEMBER' then ( select m2.nickname from tbl_member m2 where m2.id = r.target_id ) else 'unknown' end as target_name, case when r.target_type = 'WORK' then ( select w.member_id from tbl_work w where w.id = r.target_id ) when r.target_type = 'MEMBER' then r.target_id else null end as target_author_id, ( select count(*) from tbl_report r2 where r2.target_type = r.target_type and r2.target_id = r.target_id ) as target_report_count from tbl_report r join tbl_member m on r.reporter_id = m.id
and ( m.nickname ilike '%' || #{keyword} || '%' or r.detail ilike '%' || #{keyword} || '%' )
and r.target_type = #{targetType}
and r.status = #{status}
and r.reporter_id = #{reporterId}
order by r.created_datetime desc limit #{size} offset #{offset}

select count(*)
from tbl_report r
join tbl_member m on r.reporter_id = m.id


        and (
            m.nickname ilike '%' || #{keyword} || '%'
            or r.detail ilike '%' || #{keyword} || '%'
        )


        and r.target_type = #{targetType}


        and r.status = #{status}


        and r.reporter_id = #{reporterId}
